  ('aboriginal-d0d1b9a2-moex-00008', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依中央總會計制度之規定，有關公務機關繳付公庫數分析表，其中表列收入合計數列之各欄金額 分別為：收入實現數3,000億元、預收款200億元、收入待納庫數300億元、以前年度待納庫繳 庫數100億元、收到以前年度剔除經費100億元，則繳付公庫數欄應列之金額為何？', '["3,700億元", "3,600億元", "3,300億元", "3,100億元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "f28ec9747297", "answer_pdf_sha1": "297856bc2cb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
